16	// --- String boundary consts for slug wire format ---
17	
18	pub(crate) const JJRZ_SLUG_SLATE: &str = "jjezs_slate";
19	pub(crate) const JJRZ_SLUG_RESLATE: &str = "jjezs_reslate";
20	pub(crate) const JJRZ_SLUG_PADDOCK: &str = "jjezs_paddock";
21	pub(crate) const JJRZ_SLUG_PACE: &str = "jjezs_pace";
