111	/// Convert handler (exit_code, output) to MCP CallToolResult.
112	fn jjrm_result(result: (i32, String)) -> Result<CallToolResult, McpError> {
113	    let (code, output) = result;
114	    if code == 0 {
115	        Ok(CallToolResult::success(vec![Content::text(output)]))
116	    } else {
117	        Ok(CallToolResult::error(vec![Content::text(output)]))
118	    }
119	}
